+func TestContainsBeadsMarkerLegacy(t *testing.T) {
+	content := "# Header\n\n<!-- BEGIN BEADS INTEGRATION -->\nContent\n<!-- END BEADS INTEGRATION -->\n"
+	if !containsBeadsMarker(content) {
+		t.Error("should detect legacy marker")
+	}
+}
