+	content := "# Header\n\n<!-- BEGIN BEADS INTEGRATION profile:full hash:a1b2c3d4 -->\nContent\n<!-- END BEADS INTEGRATION -->\n"
+	if !containsBeadsMarker(content) {
+		t.Error("should detect new-format marker")
+	}
+}
